import re
import shutil
import subprocess
import tempfile
from pathlib import Path
from typing import List

import pytest

import crosstl.translator
from crosstl.translator.ast import (
    BlockNode,
    ConstructorNode,
    ExecutionModel,
    FunctionNode,
    IdentifierNode,
    LiteralNode,
    PrimitiveType,
    ShaderNode,
    ShaderStage,
    StageNode,
    StructMemberNode,
    StructNode,
    VariableNode,
    VectorType,
    WaveOpNode,
)
from crosstl.translator.codegen.metal_codegen import MetalCodeGen
from crosstl.translator.lexer import Lexer
from crosstl.translator.parser import Parser


def tokenize_code(code: str) -> List:
    lexer = Lexer(code)
    return lexer.get_tokens()


def parse_code(tokens: List):
    """Helper function to parse tokens into an AST.

    Args:
        tokens (List): The list of tokens to parse
    Returns:
        AST: The abstract syntax tree generated from the parser
    """
    parser = Parser(tokens)
    return parser.parse()


def generate_code(ast_node):
    """Test the code generator
    Args:
        ast_node: The abstract syntax tree generated from the code
    Returns:
        str: The generated code from the abstract syntax tree
    """
    codegen = MetalCodeGen()
    return codegen.generate(ast_node)


def compile_with_metal_if_available(source: str):
    xcrun = shutil.which("xcrun")
    if xcrun is None:
        pytest.skip("xcrun is not available")

    lookup = subprocess.run(
        [xcrun, "-f", "metal"],
        capture_output=True,
        check=False,
        text=True,
    )
    if lookup.returncode != 0:
        pytest.skip("Metal compiler is not available")

    with tempfile.TemporaryDirectory() as temp_dir:
        source_path = Path(temp_dir) / "shader.metal"
        output_path = Path(temp_dir) / "shader.air"
        source_path.write_text(source)
        result = subprocess.run(
            [xcrun, "metal", str(source_path), "-o", str(output_path)],
            capture_output=True,
            check=False,
            text=True,
        )

    assert result.returncode == 0, result.stderr


def test_metal_codegen_skips_resource_array_hint_walk_without_resource_arrays():
    shader = """
    shader MetalBlendOverloadShape {
        fragment {
            vec4 blend(vec4 backdrop, vec4 source, float intensity) {
                vec4 blendedColor = blend(backdrop, source);
                return mix(backdrop, blendedColor, intensity);
            }
        }
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(shader)))

    assert "float4 blendedColor = blend(backdrop, source);" in generated_code
    assert "return mix(backdrop, blendedColor, intensity);" in generated_code


def test_glsl_vertex_layout_locations_lower_to_metal_attributes(tmp_path):
    shader = """
    #version 330 core
    layout(location = 0) in vec3 Position;
    layout(location = 3) in vec3 Color;

    out vec3 vertColor;
    uniform mat4 MVP;

    void main() {
        vertColor = Color;
        gl_Position = MVP * vec4(Position, 1.0);
    }
    """
    shader_path = tmp_path / "flat-color.vert"
    shader_path.write_text(shader)

    generated_code = crosstl.translate(
        str(shader_path),
        backend="metal",
        format_output=False,
        source_backend="opengl",
    )

    assert "float3 Position [[attribute(0)]];" in generated_code
    assert "float3 Color [[attribute(3)]];" in generated_code
    assert "[[location" not in generated_code
    xcrun = shutil.which("xcrun")
    if xcrun is not None:
        lookup = subprocess.run(
            [xcrun, "-f", "metal"],
            capture_output=True,
            check=False,
            text=True,
        )
        if lookup.returncode == 0:
            compile_with_metal_if_available(generated_code)


def test_glsl_fragment_fragcoord_lowers_to_metal_position_input(tmp_path):
    shader = """
    #version 330 core
    out vec4 fragColor;

    void main() {
        if (mod(gl_FragCoord.x, 2.0) < 1.0 ||
            mod(gl_FragCoord.y, 2.0) < 1.0) {
            discard;
        }
        fragColor = vec4(1.0);
    }
    """
    shader_path = tmp_path / "noise.frag"
    shader_path.write_text(shader)

    generated_code = crosstl.translate(
        str(shader_path),
        backend="metal",
        format_output=False,
        source_backend="opengl",
    )

    assert "gl_FragCoord" not in generated_code
    assert "float4 _crossglFragCoord [[position]]" in generated_code
    assert "_crossglFragCoord.x" in generated_code
    assert "_crossglFragCoord.y" in generated_code
    compile_with_metal_if_available(generated_code)


def test_glsl_push_constant_vertex_output_synthesizes_metal_position(tmp_path):
    shader = """
    #version 400

    layout(push_constant) uniform Material {
        int kind;
        float fa[3];
    } matInst;

    out vec4 color;

    void main()
    {
        switch (matInst.kind) {
        case 1:  color = vec4(0.2); break;
        case 2:  color = vec4(0.5); break;
        default: color = vec4(0.0); break;
        }
    }
    """
    shader_path = tmp_path / "spv.pushConstant.vert"
    shader_path.write_text(shader)

    generated_code = crosstl.translate(
        str(shader_path),
        backend="metal",
        format_output=False,
        source_backend="opengl",
    )

    assert "vertex VertexOutput vertex_main" in generated_code
    assert "float4 color;" in generated_code
    assert "float4 __crossgl_position [[position]];" in generated_code
    assert ".__crossgl_position = float4(0.0, 0.0, 0.0, 1.0);" in generated_code

    xcrun = shutil.which("xcrun")
    if xcrun is not None:
        lookup = subprocess.run(
            [xcrun, "-f", "metal"],
            capture_output=True,
            check=False,
            text=True,
        )
        if lookup.returncode == 0:
            compile_with_metal_if_available(generated_code)


def test_metal_resource_array_size_expression_function_calls_do_not_leak_ast_nodes():
    shader = """
    shader MetalResourceArrayExpressionSize {
        const int MAP_COUNT = 2;
        compute {
            layout(set = 0, binding = 1) uniform sampler2D maps[MAP_COUNT + runtimeCount()];
            void main() {
                return;
            }
        }
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(shader)))

    assert "array<texture2d<float>, MAP_COUNT + runtimeCount()> maps" in generated_code
    assert "IdentifierNode(" not in generated_code


def test_metal_stage_local_descriptor_arrays_can_reuse_source_bindings():
    # Reduced from CrossGL-Compiler
    # tests/metal/fixtures/MetalGraphicsDescriptorArrayShader.cgl.
    shader = """
    shader MetalGraphicsDescriptorArrayShader {
        const int RESOURCE_COUNT = 2;

        struct MeshVertex {
            vec3 position;
            vec2 texCoord;
        }

        struct RasterPayload {
            vec4 clipPosition;
            vec2 uv;
        }

        struct ColorTarget {
            vec4 color;
        }

        vertex {
            layout(set = 0, binding = 1) uniform sampler2D heightMaps[RESOURCE_COUNT];
            layout(set = 0, binding = 3) sampler heightSamplers[RESOURCE_COUNT];

            RasterPayload main(MeshVertex input) {
                RasterPayload output;
                vec4 height = textureLod(heightMaps[1], heightSamplers[0], input.texCoord, 0.0);
                output.clipPosition = vec4(input.position, 1.0);
                output.uv = input.texCoord + height.xy;
                return output;
            }
        }

        fragment {
            layout(set = 0, binding = 1) uniform sampler2D colorMaps[RESOURCE_COUNT];
            layout(set = 0, binding = 3) sampler linearSamplers[RESOURCE_COUNT];

            ColorTarget main(RasterPayload input) {
                ColorTarget output;
                output.color = texture(colorMaps[0], linearSamplers[1], input.uv);
                return output;
            }
        }
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(shader)))

    assert (
        "array<texture2d<float>, RESOURCE_COUNT> heightMaps [[texture(1)]]"
        in generated_code
    )
    assert (
        "array<texture2d<float>, RESOURCE_COUNT> colorMaps [[texture(3)]]"
        in generated_code
    )
    assert (
        "array<sampler, RESOURCE_COUNT> heightSamplers [[sampler(3)]]" in generated_code
    )
    assert (
        "array<sampler, RESOURCE_COUNT> linearSamplers [[sampler(5)]]" in generated_code
    )


def test_metal_mod_builtin_lowers_to_glsl_semantics_expression():
    # Apple MSL exposes fmod(), not GLSL/CrossGL mod(); real tiled shaders with
    # negative coordinates need floor-based mod semantics instead of fmod().
    shader = """
    shader MetalModuloPattern {
        compute {
            void main(uint3 tid @ gl_GlobalInvocationID) {
                vec2 uv = vec2(float(tid.x), float(tid.y));
                vec2 tile = mod((uv * 4.0) - vec2(2.0), 1.0);
                vec2 wrapped = mod(tile, vec2(0.25, 0.5));
            }
        }
    }
    """

    generated_code = MetalCodeGen().generate_stage(
        crosstl.translator.parse(shader), "compute"
    )

    assert (
        "float2 tile = ((uv * float2(4.0) - float2(2.0)) - "
        "((1.0) * floor((uv * float2(4.0) - float2(2.0)) / (1.0))));"
    ) in generated_code
    assert (
        "float2 wrapped = ((tile) - "
        "((float2(0.25, 0.5)) * floor((tile) / (float2(0.25, 0.5)))));"
    ) in generated_code
    assert "mod(" not in generated_code


def test_metal_user_defined_mod_function_is_preserved():
    shader = """
    shader MetalUserMod {
        compute {
            float mod(float value, float period) {
                return value + period;
            }

            void main(uint3 tid @ gl_GlobalInvocationID) {
                float wrapped = mod(float(tid.x), 2.0);
            }
        }
    }
    """

    generated_code = MetalCodeGen().generate_stage(
        crosstl.translator.parse(shader), "compute"
    )

    assert "float mod(float value, float period)" in generated_code
    assert "float wrapped = mod(float(tid.x), 2.0);" in generated_code
    assert "floor(" not in generated_code


