    assert (
        "image.write(uint4(oldValue + value), uint2(pixelLayer.xy), uint(pixelLayer.z));"
        in generated_code
    )
    assert "[[r32" not in generated_code
    assert "imageLoad(" not in generated_code
    assert "imageStore(" not in generated_code


