    assert (
        "array<texture2d<float, access::read_write>, 3> rgPairs [[texture(2)]]"
        in generated_code
    )
    assert (
        "array<texture3d<float, access::read_write>, 2> rgbaVolumes [[texture(5)]]"
        in generated_code
    )
    assert (
        "texture2d<uint, access::read_write> afterCounters [[texture(7)]]"
        in generated_code
    )
