def test_metal_storage_image_levels_and_lod_queries_emit_diagnostics():
    shader = """
    shader StorageImageInvalidQueries {
        image2D colorImage;
        image3D volumeImage;
        image2DArray layerImage;
        uimage2D uintImage;
        iimage3D intVolume;

        struct FSInput {
            vec2 uv @ TEXCOORD0;
            vec3 uvw @ TEXCOORD1;
        };

        int imageLevels(image2D image) {
            return textureQueryLevels(image);
        }

        vec2 imageLod(image2D image, vec2 uv) {
            return textureQueryLod(image, uv);
        }

        int volumeLevels(image3D image) {
            return textureQueryLevels(image);
        }

        vec2 volumeLod(image3D image, vec3 uvw) {
            return textureQueryLod(image, uvw);
        }

        fragment {
            vec4 main(FSInput input) @ gl_FragColor {
                int levels = textureQueryLevels(colorImage)
                    + textureQueryLevels(volumeImage)
                    + textureQueryLevels(layerImage)
                    + textureQueryLevels(uintImage)
                    + textureQueryLevels(intVolume);
                vec2 lod = textureQueryLod(colorImage, input.uv)
                    + textureQueryLod(volumeImage, input.uvw)
                    + imageLod(colorImage, input.uv)
                    + volumeLod(volumeImage, input.uvw);
                return vec4(float(levels) + lod.x);
            }
        }
    }
    """

    generated_code = MetalCodeGen().generate_stage(
        crosstl.translator.parse(shader), "fragment"
    )

    assert (
        generated_code.count(
            "/* unsupported Metal texture query: textureQueryLevels on texture2d<float, access::read_write> */ 0"
        )
        == 2
    )
    assert (
        generated_code.count(
            "/* unsupported Metal texture query: textureQueryLevels on texture3d<float, access::read_write> */ 0"
        )
        == 2
    )
    assert (
        "/* unsupported Metal texture query: textureQueryLevels on texture2d_array<float, access::read_write> */ 0"
        in generated_code
    )
    assert (
        "/* unsupported Metal texture query: textureQueryLevels on texture2d<uint, access::read_write> */ 0"
        in generated_code
    )
    assert (
        "/* unsupported Metal texture query: textureQueryLevels on texture3d<int, access::read_write> */ 0"
        in generated_code
    )
    assert (
        generated_code.count(
            "/* unsupported Metal texture query: textureQueryLod on texture2d<float, access::read_write> */ float2(0.0)"
        )
        == 2
    )
    assert (
        generated_code.count(
            "/* unsupported Metal texture query: textureQueryLod on texture3d<float, access::read_write> */ float2(0.0)"
        )
        == 2
    )
    assert "textureQueryLevels(" not in generated_code
    assert "textureQueryLod(" not in generated_code
    assert "calculate_unclamped_lod" not in generated_code
    assert "calculate_clamped_lod" not in generated_code
    assert "sampler(" not in generated_code


def test_metal_texture_query_functions():
    shader = """
    shader TextureQueries {
        sampler2D colorMap;
        sampler2DArray layerMap;
        sampler2DMS msMap;
        sampler linearSampler;

        struct VSOutput {
            vec2 uv;
        };

        ivec2 query2D(sampler2D tex, sampler s, vec2 uv) {
            ivec2 size = textureSize(tex, 1);
            int levels = textureQueryLevels(tex);
            vec2 lod = textureQueryLod(tex, s, uv);
            return size + ivec2(levels) + ivec2(lod);
        }

        ivec3 queryArray(sampler2DArray tex) {
            return textureSize(tex, 0);
        }

        ivec2 queryMs(sampler2DMS tex) {
            return textureSize(tex);
        }

        fragment {
            vec4 main(VSOutput input) @ gl_FragColor {
                ivec2 q = query2D(colorMap, linearSampler, input.uv);
                ivec3 qa = queryArray(layerMap);
                ivec2 qm = queryMs(msMap);
                return vec4(q.x + qa.z + qm.x);
            }
        }
    }
    """

    ast = crosstl.translator.parse(shader)
    generated_code = MetalCodeGen().generate(ast)

    assert "texture2d<float> colorMap [[texture(0)]]" in generated_code
    assert "texture2d_array<float> layerMap [[texture(1)]]" in generated_code
    assert "texture2d_ms<float> msMap [[texture(2)]]" in generated_code
    assert "sampler linearSampler [[sampler(0)]]" in generated_code
    assert (
        "int2 size = int2(tex.get_width(uint(1)), tex.get_height(uint(1)));"
        in generated_code
    )
    assert "int levels = int(tex.get_num_mip_levels());" in generated_code
    assert (
        "float2 lod = float2(tex.calculate_clamped_lod(s, uv), tex.calculate_unclamped_lod(s, uv));"
        in generated_code
    )
    assert (
        "return int3(tex.get_width(uint(0)), tex.get_height(uint(0)), tex.get_array_size());"
        in generated_code
    )
    assert "return int2(tex.get_width(), tex.get_height());" in generated_code


def test_metal_struct_resource_array_queries_use_constant_index_metadata():
    shader = """
    shader StructResourceArrayQueries {
        struct TexturePack {
            sampler2D textures[4];
            sampler2DArray layers[4];
            sampler2DMS msTextures[4];
            sampler2DMSArray msArrays[4];
        };

        int query(TexturePack pack, vec3 uvLayer) {
            constant int LAYER = 2;
            ivec2 dims = textureSize(pack.textures[LAYER], LAYER);
            ivec3 layerDims = textureSize(pack.layers[LAYER], 1);
            int levels = textureQueryLevels(pack.textures[LAYER]);
            vec2 lod = textureQueryLod(pack.layers[LAYER], uvLayer);
            int samples = textureSamples(pack.msTextures[LAYER])
                + imageSamples(pack.msArrays[LAYER]);
            return dims.x + layerDims.z + levels + int(lod.x) + samples;
        }

        fragment {
            vec4 main() @ gl_FragColor {
                TexturePack pack;
                int value = query(pack, vec3(0.5, 0.25, 1.0));
                return vec4(float(value));
            }
        }
    }
    """

    generated_code = MetalCodeGen().generate_stage(
        crosstl.translator.parse(shader), "fragment"
    )
    default_sampler = "sampler(mag_filter::linear, min_filter::linear)"

    assert "array<texture2d<float>, 4> textures;" in generated_code
    assert "array<texture2d_array<float>, 4> layers;" in generated_code
    assert "array<texture2d_ms<float>, 4> msTextures;" in generated_code
    assert "array<texture2d_ms_array<float>, 4> msArrays;" in generated_code
    assert "constexpr int LAYER = 2;" in generated_code
    assert (
        "int2 dims = int2(pack.textures[LAYER].get_width(uint(LAYER)), pack.textures[LAYER].get_height(uint(LAYER)));"
        in generated_code
    )
    assert (
        "int3 layerDims = int3(pack.layers[LAYER].get_width(uint(1)), pack.layers[LAYER].get_height(uint(1)), pack.layers[LAYER].get_array_size());"
        in generated_code
    )
    assert (
        "int levels = int(pack.textures[LAYER].get_num_mip_levels());" in generated_code
    )
    assert (
        f"float2 lod = float2(pack.layers[LAYER].calculate_clamped_lod({default_sampler}, uvLayer.xy), pack.layers[LAYER].calculate_unclamped_lod({default_sampler}, uvLayer.xy));"
        in generated_code
    )
    assert (
        "int samples = int(pack.msTextures[LAYER].get_num_samples()) + int(pack.msArrays[LAYER].get_num_samples());"
        in generated_code
    )
    assert "textureSize(" not in generated_code
    assert "textureQueryLod(" not in generated_code
    assert "textureSamples(" not in generated_code
    assert "imageSamples(" not in generated_code
    assert "unsupported Metal texture samples query" not in generated_code


def test_metal_nested_resource_container_array_fields_forward_to_helpers():
    shader = """
    shader NestedResourceContainerForwarding {
        struct TexturePack {
            sampler2D textures[4];
            sampler2DArray layers[4];
        };

        struct ResourceBank {
            TexturePack pack;
            sampler samplers[4];
        };

        vec4 samplePack(
            TexturePack pack,
            sampler samplers[4],
            vec2 uv,
            vec3 uvLayer
        ) {
            constant int LAYER = 2;
            vec4 planar = texture(pack.textures[LAYER], samplers[LAYER], uv);
            vec4 layered = texture(pack.layers[LAYER], samplers[LAYER], uvLayer);
            return planar + layered;
        }

        vec4 sampleBank(ResourceBank bank, vec2 uv, vec3 uvLayer) {
            return samplePack(bank.pack, bank.samplers, uv, uvLayer);
        }

        fragment {
            vec4 main() @ gl_FragColor {
                ResourceBank bank;
                return sampleBank(
                    bank,
                    vec2(0.5, 0.25),
                    vec3(0.25, 0.75, 1.0)
                );
            }
        }
    }
    """

    generated_code = MetalCodeGen().generate_stage(
        crosstl.translator.parse(shader), "fragment"
    )

    assert "array<texture2d<float>, 4> textures;" in generated_code
    assert "array<texture2d_array<float>, 4> layers;" in generated_code
    assert "array<sampler, 4> samplers;" in generated_code
    assert (
        "float4 samplePack(TexturePack pack, array<sampler, 4> samplers, float2 uv, float3 uvLayer)"
        in generated_code
    )
    assert (
        "float4 planar = pack.textures[LAYER].sample(samplers[LAYER], uv);"
        in generated_code
    )
    assert (
        "float4 layered = pack.layers[LAYER].sample(samplers[LAYER], uvLayer.xy, uint(uvLayer.z));"
        in generated_code
    )
    assert "return samplePack(bank.pack, bank.samplers, uv, uvLayer);" in generated_code
    assert "texture2d<float> textures[4];" not in generated_code
    assert "sampler samplers[4];" not in generated_code


